let logs = [];
try {
  const extracted = $input.first().json;
  if (Array.isArray(extracted)) { logs = extracted; }
  else if (extracted && extracted.data && Array.isArray(extracted.data)) { logs = extracted.data; }
} catch(e) { logs = []; }
const body = $('Webhook').first().json.body || {};

if (body.deleteSource) {
  logs = logs.filter(l => l.source !== body.deleteSource);
  return [{ json: { logsStr: JSON.stringify(logs, null, 2), total: logs.length, deleted: true } }];
}

if (body.deleteContactId) {
  logs = logs.filter(l => l.contactId !== body.deleteContactId);
  return [{ json: { logsStr: JSON.stringify(logs, null, 2), total: logs.length, deleted: true } }];
}

const entryDate = body.date || new Date().toISOString().split('T')[0];
const entryTs   = body.timestamp || (entryDate + 'T12:00:00.000Z');

const entry = {
  id:          Date.now().toString(36) + Math.random().toString(36).slice(2),
  timestamp:   entryTs,
  date:        entryDate,
  type:        body.type        || 'test',
  contactId:   body.contactId   || 'test-id',
  contactName: body.contactName || 'Test User',
  phone:       body.phone       || '0000',
  points:      Number(body.points) || 0,
  source:      body.source      || 'test',
  invoiceId:   body.invoiceId   || null,
  siigoId:     body.siigoId     || null
};
logs.push(entry);
return [{ json: { logsStr: JSON.stringify(logs, null, 2), entry, total: logs.length } }];
